31	// Enum for command line option IDs (using traditional enum for C library compatibility)
32	enum LLMBuildOptionId : int
33	{
34	    HELP = 701,
35	    ONNX_DIR = 702,
36	    ENGINE_DIR = 703,
37	    MAX_INPUT_LEN = 704,
38	    MAX_KV_CACHE_CAPACITY = 705,
