49	struct LLMBuildArgs
50	{
51	    bool help{false};
52	    std::string onnxDir;
53	    std::string engineDir;
54	    int64_t maxInputLen{1024};
55	    int64_t maxKVCacheCapacity{4096};
56	    bool debug{false};
57	    int64_t maxBatchSize{4};
58	    int64_t maxLoraRank{0}; // Default to 0 means no LoRA
59	    bool specDraft{false};
60	    bool specBase{false};
61	    int64_t maxVerifyTreeSize{60};
62	    int64_t maxDraftTreeSize{60};
63	    bool profilingDetailed{false}; // Enable detailed profiling verbosity for layer info extraction
64	};
65	
66	void printUsage(char const* programName)
67	{
68	    std::cerr << "Usage: " << programName
69	              << " [--help] --onnxDir <dir> --engineDir <dir> [--maxInputLen <int>] "
70	                 "[--maxKVCacheCapacity <int>] [--maxBatchSize <int>] [--debug] [--maxLoraRank <int>]"
71	                 "[--specDraft] [--specBase] [--maxVerifyTreeSize <int>] "
72	                 "[--maxDraftTreeSize <int>] [--profilingDetailed]"
73	              << std::endl;
74	    std::cerr << "Options:" << std::endl;
75	    std::cerr << "  --help                    Display this help message" << std::endl;
76	    std::cerr << "  --onnxDir                 Provide the input ONNX directory path. Required. " << std::endl;
77	    std::cerr << "  --engineDir               Provide the output TensorRT engine directory path. Required. "
78	              << std::endl;
79	    std::cerr << "  --maxInputLen             Provide the maximum input length for the model. Default = 1024"
80	              << std::endl;
81	    std::cerr << "  --maxKVCacheCapacity      Provide the maximum KV cache capacity (sequence length). "
82	                 "Default = 4096"
83	              << std::endl;
84	    std::cerr << "  --maxBatchSize            Provide the maximum batch_size for builder. Default = 4" << std::endl;
85	    std::cerr << "  --debug                   Use debug mode, which outputs more logs." << std::endl;
86	    std::cerr << "  --maxLoraRank             Maximum LoRA rank for dynamic LoRA adaptation. Default = 0 (no LoRA)"
87	              << std::endl;
88	    std::cerr << "  --specDraft               Build as speculative decoding draft model (EAGLE/MTP/DFlash)"
89	              << std::endl;
90	    std::cerr << "  --specBase                Build as speculative decoding base model (EAGLE/MTP/DFlash)" << std::endl;
91	    std::cerr << "  --maxVerifyTreeSize       Maximum input_ids tokens for base model verification. Default = 60"
92	              << std::endl;
93	    std::cerr << "  --maxDraftTreeSize        Maximum input_ids tokens for draft model generation. Default = 60"
94	              << std::endl;
95	    std::cerr << "  --profilingDetailed       Enable detailed profiling verbosity to include ONNX op names "
96	                 "in layer info. Use for DLSim analysis."
97	              << std::endl
98	              << std::endl;
99	}
