101	bool parseLLMBuildArgs(LLMBuildArgs& args, int argc, char* argv[])
102	{
103	    static struct option buildOptions[] = {{"help", no_argument, 0, LLMBuildOptionId::HELP},
104	        {"onnxDir", required_argument, 0, LLMBuildOptionId::ONNX_DIR},
105	        {"engineDir", required_argument, 0, LLMBuildOptionId::ENGINE_DIR},
106	        {"maxInputLen", required_argument, 0, LLMBuildOptionId::MAX_INPUT_LEN},
107	        {"maxKVCacheCapacity", required_argument, 0, LLMBuildOptionId::MAX_KV_CACHE_CAPACITY},
108	        {"debug", no_argument, 0, LLMBuildOptionId::DEBUG},
109	        {"maxBatchSize", required_argument, 0, LLMBuildOptionId::MAX_BATCH_SIZE},
110	        {"maxLoraRank", required_argument, 0, LLMBuildOptionId::MAX_LORA_RANK},
111	        {"specDraft", no_argument, 0, LLMBuildOptionId::SPEC_DRAFT},
112	        {"eagleDraft", no_argument, 0, LLMBuildOptionId::SPEC_DRAFT}, // deprecated alias
113	        {"specBase", no_argument, 0, LLMBuildOptionId::SPEC_BASE},
114	        {"eagleBase", no_argument, 0, LLMBuildOptionId::SPEC_BASE}, // deprecated alias
115	        {"maxVerifyTreeSize", required_argument, 0, LLMBuildOptionId::MAX_VERIFY_TREE_SIZE},
116	        {"maxDraftTreeSize", required_argument, 0, LLMBuildOptionId::MAX_DRAFT_TREE_SIZE},
117	        {"profilingDetailed", no_argument, 0, LLMBuildOptionId::PROFILING_DETAILED}, {0, 0, 0, 0}};
118	
119	    int opt;
120	    while ((opt = getopt_long(argc, argv, "", buildOptions, nullptr)) != -1)
121	    {
122	        switch (opt)
123	        {
124	        case LLMBuildOptionId::HELP: args.help = true; return true;
125	        case LLMBuildOptionId::ONNX_DIR:
126	            if (optarg)
127	            {
128	                args.onnxDir = optarg;
129	            }
130	            else
131	            {
132	                LOG_ERROR("--onnxDir requires option argument.");
133	                return false;
134	            }
135	            break;
136	        case LLMBuildOptionId::ENGINE_DIR:
137	            if (optarg)
138	            {
139	                args.engineDir = optarg;
140	            }
141	            else
142	            {
143	                LOG_ERROR("--engineDir requires option argument.");
144	                return false;
145	            }
146	            break;
147	        case LLMBuildOptionId::MAX_INPUT_LEN:
148	            if (optarg)
149	            {
150	                args.maxInputLen = std::stoi(optarg);
151	            }
152	            break;
153	        case LLMBuildOptionId::MAX_KV_CACHE_CAPACITY:
154	            if (optarg)
155	            {
156	                args.maxKVCacheCapacity = std::stoi(optarg);
157	            }
158	            break;
159	        case LLMBuildOptionId::DEBUG: args.debug = true; break;
160	        case LLMBuildOptionId::MAX_BATCH_SIZE:
161	            if (optarg)
162	            {
163	                args.maxBatchSize = std::stoi(optarg);
164	            }
165	            break;
166	        case LLMBuildOptionId::MAX_LORA_RANK:
167	            if (optarg)
168	            {
169	                args.maxLoraRank = std::stoi(optarg);
170	            }
171	            break;
172	        case LLMBuildOptionId::SPEC_DRAFT: args.specDraft = true; break;
173	        case LLMBuildOptionId::SPEC_BASE: args.specBase = true; break;
174	        case LLMBuildOptionId::MAX_VERIFY_TREE_SIZE:
175	            if (optarg)
176	            {
177	                args.maxVerifyTreeSize = std::stoi(optarg);
178	            }
179	            break;
180	        case LLMBuildOptionId::MAX_DRAFT_TREE_SIZE:
181	            if (optarg)
182	            {
183	                args.maxDraftTreeSize = std::stoi(optarg);
184	            }
185	            break;
186	        case LLMBuildOptionId::PROFILING_DETAILED: args.profilingDetailed = true; break;
187	        default: LOG_ERROR("Invalid Argument %c is %s.", opt, optarg); return false;
188	        }
189	    }
190	    return true;
191	}
192	
193	int main(int argc, char** argv)
194	{
195	    LLMBuildArgs args;
196	    if ((argc < 2) || (!parseLLMBuildArgs(args, argc, argv)))
197	    {
198	        LOG_ERROR("Unable to parse builder args.");
199	        printUsage(argv[0]);
200	        return EXIT_FAILURE;
201	    }
202	    if (args.help)
203	    {
204	        printUsage(argv[0]);
205	        return EXIT_SUCCESS;
206	    }
207	
208	    if (args.debug)
209	    {
210	        gLogger.setLevel(nvinfer1::ILogger::Severity::kVERBOSE);
211	    }
212	    else
213	    {
214	        gLogger.setLevel(nvinfer1::ILogger::Severity::kINFO);
215	    }
216	
217	    // Validate input directory and required files
218	    std::string configPath = args.onnxDir + "/config.json";
219	    std::ifstream configFile(configPath);
220	    if (!configFile.good())
221	    {
222	        LOG_ERROR("config.json not found in onnx directory: %s", args.onnxDir.c_str());
223	        return EXIT_FAILURE;
224	    }
225	    configFile.close();
226	
227	    // Create LLMBuilderConfig from args
228	    builder::LLMBuilderConfig config;
229	    config.maxInputLen = args.maxInputLen;
230	    config.maxKVCacheCapacity = args.maxKVCacheCapacity;
231	    config.maxBatchSize = args.maxBatchSize;
232	    config.maxLoraRank = args.maxLoraRank;
233	    config.specDraft = args.specDraft;
234	    config.specBase = args.specBase;
235	    config.maxVerifyTreeSize = args.maxVerifyTreeSize;
236	    config.maxDraftTreeSize = args.maxDraftTreeSize;
237	    config.profilingDetailed = args.profilingDetailed;
238	
239	    // Create and run the builder
240	    builder::LLMBuilder llmBuilder(args.onnxDir, args.engineDir, config);
241	    if (!llmBuilder.build())
242	    {
243	        LOG_ERROR("Failed to build LLM engine.");
244	        return EXIT_FAILURE;
245	    }
246	
247	    LOG_INFO("LLM engine built successfully.");
248	    return EXIT_SUCCESS;
249	}
