51	// Enum for command line option IDs (using traditional enum for C library compatibility)
52	enum LLMInferenceOptionId : int
53	{
54	    HELP = 900,
55	    INPUT_FILE = 901,
56	    ENGINE_DIR = 902,
57	    MULTIMODAL_ENGINE_DIR = 903,
58	    OUTPUT_FILE = 904,
59	    DEBUG = 905,
60	    DUMP_PROFILE = 906,
61	    PROFILE_OUTPUT_FILE = 907,
62	    WARMUP = 908,
63	    DUMP_OUTPUT = 909,
