79	// Struct to hold speculative decoding arguments (used by both EAGLE and MTP)
80	struct SpecDecodeArgs
81	{
82	    bool enabled{false};
83	
84	    // Number of tokens selected per drafting step from the draft model's output distribution.
85	    // For tree-based strategies this is the branching factor; for chain-style
86	    // strategies it is the number of candidates retained per draft step.
87	    int32_t draftTopK{10};
88	
89	    // Number of drafting steps to perform with the draft model.
90	    // Each step extends the current draft proposal.
91	    int32_t draftStep{6};
92	
93	    // Number of proposal tokens to select for base model verification.
94	    int32_t verifySize{60};
95	
96	    // DFlash-only draft horizon. 0 means infer from the engine config.
97	    int32_t dflashBlockSize{0};
98	};
