100	struct LLMInferenceArgs
101	{
102	    bool help{false};
103	    std::string engineDir;
104	    std::string multimodalEngineDir{""};
105	    std::string inputFile;
106	    std::string outputFile{""};
107	    std::string profileOutputFile{""};
108	    bool debug{false};
109	    bool dumpProfile{false};
110	    int32_t warmup{0};
111	    bool dumpOutput{false};
112	    // Override parameters (only batchSize, maxGenerateLength, and numLogprobs can be overridden via CLI)
113	    // For other sampling parameters (temperature, top_p, top_k), please specify them in the input JSON file
114	    int32_t batchSize{-1};         // -1 means use value from input file
115	    int64_t maxGenerateLength{-1}; // -1 means use value from input file
116	    int32_t numLogprobs{-1};       // -1 means use value from input file
117	    SpecDecodeArgs specDecodeArgs;
118	
119	    // Qwen3-Omni audio output options
120	    bool enableAudioOutput{false};
121	    std::string talkerEngineDir{""};
122	    std::string code2wavEngineDir{""};
123	    std::string outputAudioDir{""};
124	
125	    // Talker sampling params (read from input JSON, defaults match qwen3_tts_inference)
126	    float talkerTemperature{0.9f};
127	    int32_t talkerTopK{50};
128	    float talkerTopP{1.0f};
129	    float talkerRepetitionPenalty{1.05f};
130	
131	    // Thinker-Talker streaming mode (single CUDA stream interleaved).
132	    // All fields below can be set either via CLI flag or the top-level
