187	bool parseLLMInferenceArgs(LLMInferenceArgs& args, int argc, char* argv[])
188	{
189	    static struct option inferenceOptions[] = {{"help", no_argument, 0, LLMInferenceOptionId::HELP},
190	        {"inputFile", required_argument, 0, LLMInferenceOptionId::INPUT_FILE},
191	        {"engineDir", required_argument, 0, LLMInferenceOptionId::ENGINE_DIR},
192	        {"multimodalEngineDir", required_argument, 0, LLMInferenceOptionId::MULTIMODAL_ENGINE_DIR},
193	        {"outputFile", required_argument, 0, LLMInferenceOptionId::OUTPUT_FILE},
194	        {"debug", no_argument, 0, LLMInferenceOptionId::DEBUG},
195	        {"dumpProfile", no_argument, 0, LLMInferenceOptionId::DUMP_PROFILE},
196	        {"profileOutputFile", required_argument, 0, LLMInferenceOptionId::PROFILE_OUTPUT_FILE},
197	        {"warmup", required_argument, 0, LLMInferenceOptionId::WARMUP},
198	        {"dumpOutput", no_argument, 0, LLMInferenceOptionId::DUMP_OUTPUT},
199	        {"specDecode", no_argument, 0, LLMInferenceOptionId::SPEC_DECODE},
200	        {"eagle", no_argument, 0, LLMInferenceOptionId::SPEC_DECODE}, // deprecated alias
201	        {"specDraftTopK", required_argument, 0, LLMInferenceOptionId::SPEC_DRAFT_TOP_K},
202	        {"eagleDraftTopK", required_argument, 0, LLMInferenceOptionId::SPEC_DRAFT_TOP_K}, // deprecated alias
203	        {"specDraftStep", required_argument, 0, LLMInferenceOptionId::SPEC_DRAFT_STEP},
204	        {"eagleDraftStep", required_argument, 0, LLMInferenceOptionId::SPEC_DRAFT_STEP}, // deprecated alias
205	        {"specVerifySize", required_argument, 0, LLMInferenceOptionId::SPEC_VERIFY_SIZE},
206	        {"specVerifyTreeSize", required_argument, 0, LLMInferenceOptionId::SPEC_VERIFY_SIZE},
207	        {"eagleVerifyTreeSize", required_argument, 0, LLMInferenceOptionId::SPEC_VERIFY_SIZE}, // deprecated alias
208	        {"dflashBlockSize", required_argument, 0, LLMInferenceOptionId::DFLASH_BLOCK_SIZE},
209	        {"batchSize", required_argument, 0, LLMInferenceOptionId::BATCH_SIZE},
210	        {"maxGenerateLength", required_argument, 0, LLMInferenceOptionId::MAX_GENERATE_LENGTH},
211	        {"numLogprobs", required_argument, 0, LLMInferenceOptionId::NUM_LOGPROBS},
212	        {"enableAudioOutput", no_argument, 0, LLMInferenceOptionId::ENABLE_AUDIO_OUTPUT},
213	        {"talkerEngineDir", required_argument, 0, LLMInferenceOptionId::TALKER_ENGINE_DIR},
214	        {"code2wavEngineDir", required_argument, 0, LLMInferenceOptionId::CODE2WAV_ENGINE_DIR},
215	        {"outputAudioDir", required_argument, 0, LLMInferenceOptionId::OUTPUT_AUDIO_DIR},
216	        {"enableThinkerTalkerStreaming", no_argument, 0, LLMInferenceOptionId::ENABLE_THINKER_TALKER_STREAMING},
217	        {0, 0, 0, 0}};
218	
219	    int opt;
220	    while ((opt = getopt_long(argc, argv, "", inferenceOptions, nullptr)) != -1)
221	    {
222	        switch (opt)
223	        {
224	        case LLMInferenceOptionId::HELP: args.help = true; return true;
225	        case LLMInferenceOptionId::INPUT_FILE: args.inputFile = optarg; break;
226	        case LLMInferenceOptionId::ENGINE_DIR: args.engineDir = optarg; break;
227	        case LLMInferenceOptionId::MULTIMODAL_ENGINE_DIR: args.multimodalEngineDir = optarg; break;
228	        case LLMInferenceOptionId::OUTPUT_FILE: args.outputFile = optarg; break;
229	        case LLMInferenceOptionId::DEBUG: args.debug = true; break;
230	        case LLMInferenceOptionId::DUMP_PROFILE: args.dumpProfile = true; break;
231	        case LLMInferenceOptionId::PROFILE_OUTPUT_FILE: args.profileOutputFile = optarg; break;
232	        case LLMInferenceOptionId::WARMUP:
233	            try
234	            {
235	                args.warmup = std::stoi(optarg);
236	                if (args.warmup < 0)
237	                {
238	                    LOG_ERROR("Invalid warmup value: %s (must be non-negative)", optarg);
239	                    return false;
240	                }
241	            }
242	            catch (std::exception const& e)
243	            {
244	                LOG_ERROR("Invalid warmup value: %s", optarg);
245	                return false;
246	            }
247	            break;
248	        case LLMInferenceOptionId::DUMP_OUTPUT: args.dumpOutput = true; break;
249	        case LLMInferenceOptionId::SPEC_DECODE: args.specDecodeArgs.enabled = true; break;
250	        case LLMInferenceOptionId::SPEC_DRAFT_TOP_K:
251	            try
252	            {
253	                args.specDecodeArgs.draftTopK = std::stoi(optarg);
254	                if (args.specDecodeArgs.draftTopK <= 0)
255	                {
256	                    LOG_ERROR("Invalid specDraftTopK value: %s (must be positive)", optarg);
257	                    return false;
258	                }
259	            }
260	            catch (std::exception const& e)
261	            {
262	                LOG_ERROR("Invalid specDraftTopK value: %s", optarg);
263	                return false;
264	            }
265	            break;
266	        case LLMInferenceOptionId::SPEC_DRAFT_STEP:
267	            try
268	            {
269	                args.specDecodeArgs.draftStep = std::stoi(optarg);
270	                if (args.specDecodeArgs.draftStep <= 0)
271	                {
272	                    LOG_ERROR("Invalid specDraftStep value: %s (must be positive)", optarg);
273	                    return false;
274	                }
275	            }
276	            catch (std::exception const& e)
277	            {
278	                LOG_ERROR("Invalid specDraftStep value: %s", optarg);
279	                return false;
280	            }
281	            break;
282	        case LLMInferenceOptionId::SPEC_VERIFY_SIZE:
283	            try
284	            {
285	                args.specDecodeArgs.verifySize = std::stoi(optarg);
286	                if (args.specDecodeArgs.verifySize <= 0)
287	                {
288	                    LOG_ERROR("Invalid specVerifySize value: %s (must be positive)", optarg);
289	                    return false;
290	                }
291	            }
292	            catch (std::exception const& e)
293	            {
294	                LOG_ERROR("Invalid specVerifySize value: %s", optarg);
295	                return false;
296	            }
297	            break;
298	        case LLMInferenceOptionId::DFLASH_BLOCK_SIZE:
299	            try
300	            {
301	                args.specDecodeArgs.dflashBlockSize = std::stoi(optarg);
302	                if (args.specDecodeArgs.dflashBlockSize < 0)
303	                {
304	                    LOG_ERROR("Invalid dflashBlockSize value: %s (must be non-negative)", optarg);
305	                    return false;
306	                }
307	            }
308	            catch (std::exception const& e)
309	            {
310	                LOG_ERROR("Invalid dflashBlockSize value: %s", optarg);
311	                return false;
312	            }
313	            break;
314	        case LLMInferenceOptionId::BATCH_SIZE:
315	            try
316	            {
317	                args.batchSize = std::stoi(optarg);
318	                if (args.batchSize <= 0)
319	                {
320	                    LOG_ERROR("Invalid batchSize value: %s (must be positive)", optarg);
321	                    return false;
322	                }
323	            }
324	            catch (std::exception const& e)
325	            {
326	                LOG_ERROR("Invalid batchSize value: %s", optarg);
327	                return false;
328	            }
329	            break;
330	        case LLMInferenceOptionId::MAX_GENERATE_LENGTH:
331	            try
332	            {
333	                args.maxGenerateLength = std::stoll(optarg);
334	                if (args.maxGenerateLength <= 0)
335	                {
336	                    LOG_ERROR("Invalid maxGenerateLength value: %s (must be positive)", optarg);
337	                    return false;
338	                }
339	            }
340	            catch (std::exception const& e)
341	            {
342	                LOG_ERROR("Invalid maxGenerateLength value: %s", optarg);
343	                return false;
344	            }
345	            break;
346	        case LLMInferenceOptionId::ENABLE_AUDIO_OUTPUT: args.enableAudioOutput = true; break;
347	        case LLMInferenceOptionId::TALKER_ENGINE_DIR: args.talkerEngineDir = optarg; break;
348	        case LLMInferenceOptionId::CODE2WAV_ENGINE_DIR: args.code2wavEngineDir = optarg; break;
349	        case LLMInferenceOptionId::OUTPUT_AUDIO_DIR: args.outputAudioDir = optarg; break;
350	        case LLMInferenceOptionId::ENABLE_THINKER_TALKER_STREAMING: args.enableThinkerTalkerStreaming = true; break;
351	        case LLMInferenceOptionId::NUM_LOGPROBS:
352	            try
353	            {
354	                args.numLogprobs = std::stoi(optarg);
355	                if (args.numLogprobs < 0)
356	                {
357	                    LOG_ERROR("Invalid numLogprobs value: %s (must be non-negative)", optarg);
358	                    return false;
359	                }
360	            }
361	            catch (std::exception const& e)
362	            {
363	                LOG_ERROR("Invalid numLogprobs value: %s", optarg);
364	                return false;
365	            }
366	            break;
367	        default: return false;
368	        }
369	    }
370	
371	    LOG_INFO("args.inputFile: %s", args.inputFile.c_str());
372	    if (args.inputFile.empty())
373	    {
374	        LOG_ERROR("ERROR: --inputFile is required");
375	        return false;
376	    }
377	    LOG_INFO("args.engineDir: %s", args.engineDir.c_str());
378	    if (args.engineDir.empty())
379	    {
380	        LOG_ERROR("ERROR: --engineDir is required");
381	        return false;
382	    }
383	    if (!args.multimodalEngineDir.empty())
384	    {
385	        LOG_INFO("args.multimodalEngineDir: %s", args.multimodalEngineDir.c_str());
386	    }
387	
388	    if (args.outputFile.empty())
389	    {
390	        LOG_ERROR("ERROR: --outputFile is required");
391	        return false;
392	    }
393	    LOG_INFO("args.outputFile: %s", args.outputFile.c_str());
394	
395	    if (args.dumpOutput)
396	    {
397	        LOG_INFO("args.dumpOutput: enabled");
398	    }
399	
400	    if (!args.profileOutputFile.empty())
401	    {
402	        LOG_INFO("args.profileOutputFile: %s", args.profileOutputFile.c_str());
403	    }
404	
405	    if (args.dumpProfile)
406	    {
407	        LOG_INFO("Profile dumping to console is enabled");
408	    }
409	
410	    if (args.warmup > 0)
411	    {
412	        LOG_INFO("Warmup runs: %d", args.warmup);
413	    }
414	
415	    if (args.specDecodeArgs.enabled)
416	    {
417	        LOG_INFO("Speculative decoding enabled");
418	        LOG_INFO("Spec draft topK: %d", args.specDecodeArgs.draftTopK);
419	        LOG_INFO("Spec draft step: %d", args.specDecodeArgs.draftStep);
420	        LOG_INFO("Spec verify size: %d", args.specDecodeArgs.verifySize);
421	        LOG_INFO("DFlash block size: %d", args.specDecodeArgs.dflashBlockSize);
422	    }
423	
424	    if (args.enableAudioOutput)
425	    {
426	        if (args.talkerEngineDir.empty())
427	        {
428	            LOG_ERROR("--talkerEngineDir is required when --enableAudioOutput is set");
429	            return false;
430	        }
431	        LOG_INFO("Audio output enabled");
432	        LOG_INFO("  Talker engine: %s", args.talkerEngineDir.c_str());
433	        if (!args.code2wavEngineDir.empty())
434	        {
435	            LOG_INFO("  Code2Wav engine: %s", args.code2wavEngineDir.c_str());
436	        }
437	        if (!args.outputAudioDir.empty())
438	        {
439	            LOG_INFO("  Audio output dir: %s", args.outputAudioDir.c_str());
440	        }
441	    }
442	
443	    if (args.enableThinkerTalkerStreaming)
444	    {
445	        args.enableAudioOutput = true;
446	        if (args.talkerEngineDir.empty())
447	        {
448	            LOG_ERROR("--enableThinkerTalkerStreaming requires --talkerEngineDir");
449	            return false;
450	        }
451	        LOG_INFO("Thinker-Talker streaming enabled (single CUDA stream)");
452	    }
453	
454	    if (args.debug)
455	    {
456	        gLogger.setLevel(nvinfer1::ILogger::Severity::kVERBOSE);
457	    }
458	    else
459	    {
460	        gLogger.setLevel(nvinfer1::ILogger::Severity::kINFO);
461	    }
462	
463	    return true;
464	}
