466	// Thin wrapper around the shared parser in examples/utils/requestFileParser.h.
467	std::pair<std::unordered_map<std::string, std::string>, std::vector<rt::LLMGenerationRequest>> parseInputFile(
468	    std::filesystem::path const& inputFilePath, int32_t batchSizeOverride = -1, int64_t maxGenerateLengthOverride = -1,
469	    int32_t numLogprobsOverride = -1, LLMInferenceArgs* argsOut = nullptr)
470	{
471	    auto result = exampleUtils::parseRequestFile(
472	        inputFilePath, batchSizeOverride, maxGenerateLengthOverride, numLogprobsOverride);
473	
474	    if (argsOut != nullptr && argsOut->enableAudioOutput)
475	    {
476	        std::ifstream inputFileStream(inputFilePath);
477	        if (inputFileStream.is_open())
478	        {
479	            Json inputData = Json::parse(inputFileStream);
480	            argsOut->talkerTemperature = inputData.value("talker_temperature", 0.9f);
481	            argsOut->talkerTopK = inputData.value("talker_top_k", 50);
482	            argsOut->talkerTopP = inputData.value("talker_top_p", 1.0f);
483	            argsOut->talkerRepetitionPenalty = inputData.value("repetition_penalty", 1.05f);
484	            LOG_INFO("Talker params from JSON: temperature=%.2f, topK=%d, topP=%.2f, repetitionPenalty=%.2f",
485	                argsOut->talkerTemperature, argsOut->talkerTopK, argsOut->talkerTopP, argsOut->talkerRepetitionPenalty);
486	
487	            // Thinker-Talker streaming config: top-level "streaming": {...} block.
488	            // CLI --enableThinkerTalkerStreaming takes precedence when set; JSON fills the rest.
489	            if (inputData.contains("streaming") && inputData["streaming"].is_object())
490	            {
491	                auto const& streamingCfg = inputData["streaming"];
492	                bool const jsonEnable = streamingCfg.value("enable", false);
493	                if (jsonEnable)
494	                {
495	                    argsOut->enableThinkerTalkerStreaming = true;
496	                }
497	                argsOut->codecChunkFrames = streamingCfg.value("codec_chunk_frames", argsOut->codecChunkFrames);
498	                argsOut->talkerPrefillThreshold
499	                    = streamingCfg.value("talker_prefill_threshold", argsOut->talkerPrefillThreshold);
500	                if (argsOut->enableThinkerTalkerStreaming)
501	                {
502	                    LOG_INFO(
503	                        "Thinker-Talker streaming from JSON: enable=true, codecChunkFrames=%d, "
504	                        "talkerPrefillThreshold=%d",
505	                        argsOut->codecChunkFrames, argsOut->talkerPrefillThreshold);
506	                }
507	            }
508	        }
509	    }
510	
511	    return result;
512	}
