514	int main(int argc, char* argv[])
515	{
516	    NVTX_SCOPED_RANGE(nvtx_main, "llm_inference");
517	    LLMInferenceArgs args;
518	    if (!parseLLMInferenceArgs(args, argc, argv))
519	    {
520	        printUsage(argv[0]);
521	        return EXIT_FAILURE;
522	    }
523	    if (args.help)
524	    {
525	        printUsage(argv[0]);
526	        return EXIT_SUCCESS;
527	    }
528	    bool profilerEnabled = args.dumpProfile;
529	    MemoryMonitor memoryMonitor;
530	    // Start memory monitoring at the beginning if profiling is enabled
531	    if (profilerEnabled)
532	    {
533	        memoryMonitor.start();
534	    }
535	
536	    auto pluginHandles = loadEdgellmPluginLib();
537	    // load input file and parse to requests
538	    std::unordered_map<std::string, std::string> loraWeightsMap;
539	    std::vector<rt::LLMGenerationRequest> batchedRequests;
540	    try
541	    {
542	        std::tie(loraWeightsMap, batchedRequests)
543	            = parseInputFile(args.inputFile, args.batchSize, args.maxGenerateLength, args.numLogprobs, &args);
544	        LOG_INFO("Successfully parsed %zu LoRA weights from input file.", loraWeightsMap.size());
545	        LOG_INFO("Successfully parsed %zu batches of requests from input file.", batchedRequests.size());
546	    }
547	    catch (std::exception const& e)
548	    {
549	        LOG_ERROR("Failed to parse input file: %s", e.what());
550	        return EXIT_FAILURE;
551	    }
552	
553	    if (batchedRequests.empty())
554	    {
555	        LOG_ERROR("No valid requests found in input file.");
556	        return EXIT_FAILURE;
557	    }
558	
559	    // Create unified runtime (handles both vanilla and speculative decoding modes)
560	    std::unique_ptr<rt::LLMInferenceRuntime> runtime{nullptr};
561	    cudaStream_t stream;
562	    CUDA_CHECK(cudaStreamCreateWithFlags(&stream, cudaStreamNonBlocking));
563	
564	    if (args.specDecodeArgs.enabled)
565	    {
566	        rt::SpecDecodeDraftingConfig draftingConfig;
567	        draftingConfig.draftingTopK = args.specDecodeArgs.draftTopK;
568	        draftingConfig.draftingStep = args.specDecodeArgs.draftStep;
569	        draftingConfig.verifySize = args.specDecodeArgs.verifySize;
570	        draftingConfig.dflashBlockSize = args.specDecodeArgs.dflashBlockSize;
571	        try
572	        {
573	            runtime = std::make_unique<rt::LLMInferenceRuntime>(
574	                args.engineDir, args.multimodalEngineDir, loraWeightsMap, draftingConfig, stream);
575	        }
576	        catch (std::exception const& e)
577	        {
578	            LOG_ERROR("Failed to initialize runtime with speculative decoding: %s", e.what());
579	            return EXIT_FAILURE;
580	        }
581	    }
582	    else
583	    {
584	        // Standard vanilla-only mode (no draft model)
585	        try
586	        {
587	            runtime = std::make_unique<rt::LLMInferenceRuntime>(
588	                args.engineDir, args.multimodalEngineDir, loraWeightsMap, stream);
589	        }
590	        catch (std::exception const& e)
591	        {
592	            LOG_ERROR("Failed to initialize runtime: %s", e.what());
593	            return EXIT_FAILURE;
594	        }
595	    }
596	
597	    if (!runtime->captureDecodingCUDAGraph(stream))
598	    {
599	        LOG_WARNING("Failed to capture CUDA graph for decoding, proceeding with normal engine execution.");
600	    }
601	
602	    // Initialize Qwen3-Omni audio output pipeline (TTS runtime + Code2Wav)
603	    std::unique_ptr<rt::Qwen3OmniTTSRuntime> ttsRuntime;
604	    std::unique_ptr<rt::Code2WavRunner> code2wavRunner;
605	    if (args.enableAudioOutput)
606	    {
607	        try
608	        {
609	            std::filesystem::path const codePredictorDir
610	                = std::filesystem::path(args.talkerEngineDir).parent_path() / "code_predictor";
611	            ttsRuntime = std::make_unique<rt::Qwen3OmniTTSRuntime>(
612	                args.talkerEngineDir, codePredictorDir.string(), args.engineDir, stream);
613	            LOG_INFO("TTS runtime initialized for audio output");
614	        }
615	        catch (std::exception const& e)
616	        {
617	            LOG_ERROR("Failed to initialize TTS Runtime: %s", e.what());
618	            return EXIT_FAILURE;
619	        }
620	
621	        // Code2Wav runner (optional — falls back to RVQ code output)
622	        std::filesystem::path const code2wavDir = args.code2wavEngineDir.empty()
623	            ? std::filesystem::path(args.talkerEngineDir).parent_path() / "code2wav"
624	            : std::filesystem::path(args.code2wavEngineDir);
625	        if (std::filesystem::exists(code2wavDir))
626	        {
