1149	                LOG_INFO("Profile data exported to: %s", args.profileOutputFile.c_str());
1150	            }
1151	            else
1152	            {
1153	                LOG_ERROR("Failed to open profile output file: %s", args.profileOutputFile.c_str());
1154	                return EXIT_FAILURE;
1155	            }
1156	        }
1157	        catch (std::exception const& e)
1158	        {
1159	            LOG_ERROR("Failed to write profile output file: %s", e.what());
1160	            return EXIT_FAILURE;
1161	        }
1162	    }
1163	
1164	    // Export to JSON file
1165	    try
1166	    {
1167	        std::ofstream outputFile(args.outputFile);
1168	        if (outputFile.is_open())
1169	        {
1170	            outputFile << outputData.dump(4); // Pretty print with 4 spaces indentation
1171	            outputFile.close();
1172	            LOG_INFO("All responses exported to: %s", args.outputFile.c_str());
1173	        }
1174	        else
1175	        {
1176	            LOG_ERROR("Failed to open output file: %s", args.outputFile.c_str());
1177	            return EXIT_FAILURE;
1178	        }
1179	    }
1180	    catch (std::exception const& e)
1181	    {
1182	        LOG_ERROR("Failed to write output file: %s", e.what());
1183	        return EXIT_FAILURE;
1184	    }
1185	
1186	    // Return false if any request failed
1187	    return hasFailedRequest ? EXIT_FAILURE : EXIT_SUCCESS;
1188	}
